import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Test for issue where starting a line with || causes internal error from ktlint --format
 */
class IndentationRuleOrOperatorTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Issue - Line starting with logical OR operator should not cause internal error`() {
        val code =
            """
            package com.my.lint.rules

            import com.pinterest.ktlint.rule.engine.core.api.Rule
            import com.pinterest.ktlint.rule.engine.core.api.RuleId
            import org.jetbrains.kotlin.com.intellij.lang.ASTNode

            class BreakKtlintFormatRule : Rule(
                RuleId("my-ruleset:my-rule-id"),
                Rule.About(maintainer = "Me", repositoryUrl = "repositoryUrl", issueTrackerUrl = "issueTrackerUrl")
            ) {

                override fun beforeVisitChildNodes(
                    node: ASTNode,
                    autoCorrect: Boolean,
                    emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit
                ) {

                    if (node.text.contains("this")
                        || node.text.contains("that")
                    ) {
                        emit(node.startOffset, "My violation detail", false)
                    }
                }
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue - Line starting with logical OR operator in simple expression`() {
        val code =
            """
            fun test() {
                val result = true
                    || false
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue - Line starting with logical AND operator should also work`() {
        val code =
            """
            fun test() {
                val result = true
                    && false
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue - Multiple logical OR operators`() {
        val code =
            """
            fun test() {
                if (condition1
                    || condition2
                    || condition3
                ) {
                    doSomething()
                }
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue - Mix of logical operators`() {
        val code =
            """
            fun test() {
                if (condition1
                    && condition2
                    || condition3
                ) {
                    doSomething()
                }
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

